import torch
import fairseq
import os
import glob
import subprocess

def extract_output_text(logs):
    # Placeholder function to extract output text from logs
    # This should be implemented to parse the actual logs generated by the inference command
    return logs

def extract_output_order(output_text):
    # Placeholder function to extract the order of outputs from the output text
    # This should be implemented to match the expected output format
    return [line.split(': ')[1] for line in output_text.splitlines() if line.startswith('Output:')]

device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
model_path = os.path.join(os.getcwd(), '../fairseq_resource/mms1b_all.pt')
lang = 'eng'
audio_files = glob.glob('/Dataset/speech/english/test/libri_test_other/wav/wav/1/wav/1/*.wav')
audio_files = audio_files[:10]

# Execute the inference command and capture the output logs
command = f'python -u examples/mms/asr/infer/mms_infer.py --model {model_path} --lang {lang} --audio {" ".join(audio_files)}'
logs = subprocess.check_output(command, shell=True, text=True)

# Extract output text from the logs
output_text = extract_output_text(logs)
expected_order = [os.path.basename(file) for file in audio_files]
output_text_order = extract_output_order(output_text)

# Assert that the output log order matches the expected order
assert output_text_order == expected_order, 'Output log order is incorrect'
print('Output Text:', output_text, 'Expected Order:', expected_order)